"use client";

import {
  AnimatePresence,
  motion,
  type PanInfo,
  useMotionValue,
  useReducedMotion,
  useTransform,
} from "framer-motion";
import * as React from "react";

export type SwipeDirection = "left" | "right";

export type SwipeDeckProps = Omit<
  React.HTMLAttributes<HTMLDivElement>,
  "children" | "onError"
> & {
  /** Cards, front first. */
  children?: React.ReactNode;
  /** Fired when the front card is swiped away. */
  onSwipe?: (index: number, direction: SwipeDirection) => void;
  /** Re-append swiped cards so the deck never empties. */
  loop?: boolean;
  /** Drag distance (px) past which a release dismisses the card. */
  threshold?: number;
  /** Label shown under the deck for the right/left actions. */
  actions?: { left: string; right: string };
};

type FrontCardProps = {
  exitDir: SwipeDirection;
  threshold: number;
  onDecide: (dir: SwipeDirection) => void;
  actions?: { left: string; right: string };
  children: React.ReactNode;
};

const FrontCard: React.FC<FrontCardProps> = ({
  exitDir,
  threshold,
  onDecide,
  actions,
  children,
}) => {
  const x = useMotionValue(0);
  const rotate = useTransform(x, [-220, 220], [-15, 15]);
  const likeOpacity = useTransform(x, [24, 130], [0, 1]);
  const nopeOpacity = useTransform(x, [-130, -24], [1, 0]);

  const handleDragEnd = (_e: unknown, info: PanInfo) => {
    const flung = Math.abs(info.velocity.x) > 600;
    if (info.offset.x > threshold || (flung && info.velocity.x > 0)) {
      onDecide("right");
    } else if (info.offset.x < -threshold || (flung && info.velocity.x < 0)) {
      onDecide("left");
    }
  };

  return (
    <motion.div
      className="absolute inset-0 cursor-grab touch-none active:cursor-grabbing"
      style={{ x, rotate, zIndex: 30 }}
      drag="x"
      dragSnapToOrigin
      dragElastic={0.5}
      onDragEnd={handleDragEnd}
      initial={{ scale: 0.96, y: 0, opacity: 0 }}
      animate={{ scale: 1, y: 0, opacity: 1 }}
      exit={{
        x: exitDir === "right" ? 640 : -640,
        rotate: exitDir === "right" ? 22 : -22,
        opacity: 0,
        transition: { duration: 0.32, ease: [0.22, 1, 0.36, 1] },
      }}
      transition={{ type: "spring", stiffness: 300, damping: 28 }}
      whileTap={{ scale: 1.02 }}
    >
      {children}
      {/* Directional intent badges that fade in as you drag. */}
      <motion.span
        aria-hidden
        style={{ opacity: likeOpacity }}
        className="pointer-events-none absolute left-5 top-5 rounded-md border-2 border-primary px-3 py-1 text-sm font-bold uppercase tracking-wide text-primary [transform:rotate(-12deg)]"
      >
        {actions?.right ?? "Yes"}
      </motion.span>
      <motion.span
        aria-hidden
        style={{ opacity: nopeOpacity }}
        className="pointer-events-none absolute right-5 top-5 rounded-md border-2 border-destructive px-3 py-1 text-sm font-bold uppercase tracking-wide text-destructive [transform:rotate(12deg)]"
      >
        {actions?.left ?? "No"}
      </motion.span>
    </motion.div>
  );
};

const SwipeDeck = React.forwardRef<HTMLDivElement, SwipeDeckProps>(
  (
    {
      children,
      onSwipe,
      loop = false,
      threshold = 120,
      actions,
      className,
      ...props
    },
    forwardedRef,
  ) => {
    const ref = React.useRef<HTMLDivElement>(null);
    React.useImperativeHandle(
      forwardedRef,
      () => ref.current as HTMLDivElement,
    );
    const reduce = useReducedMotion();
    const items = React.Children.toArray(children);

    // `order` holds the original indices of the cards still in the deck.
    const [order, setOrder] = React.useState(() => items.map((_, i) => i));
    const count = items.length;
    React.useEffect(() => {
      setOrder(Array.from({ length: count }, (_, i) => i));
    }, [count]);
    const [exitDir, setExitDir] = React.useState<SwipeDirection>("right");

    const swipe = React.useCallback(
      (dir: SwipeDirection) => {
        setExitDir(dir);
        setOrder((o) => {
          if (o.length === 0) return o;
          const [front, ...rest] = o;
          onSwipe?.(front as number, dir);
          return loop ? [...rest, front as number] : rest;
        });
      },
      [loop, onSwipe],
    );

    const handleKey = (e: React.KeyboardEvent) => {
      if (e.key === "ArrowLeft") {
        e.preventDefault();
        swipe("left");
      } else if (e.key === "ArrowRight") {
        e.preventDefault();
        swipe("right");
      }
    };

    const visible = order.slice(0, 3); // front + two peeking behind

    return (
      <div
        ref={ref}
        data-slot="swipe-deck"
        className={`flex flex-col items-center gap-6 ${className ?? ""}`}
        {...props}
      >
        <div className="relative aspect-[3/4] w-72 rounded-2xl">
          <AnimatePresence initial={false}>
            {visible
              .slice()
              .reverse()
              .map((itemIndex, revRank) => {
                const rank = visible.length - 1 - revRank; // 0 = front
                if (rank === 0) {
                  return (
                    <FrontCard
                      key={itemIndex}
                      exitDir={exitDir}
                      threshold={threshold}
                      onDecide={swipe}
                      actions={actions}
                    >
                      {items[itemIndex]}
                    </FrontCard>
                  );
                }
                return (
                  <motion.div
                    key={itemIndex}
                    className="absolute inset-0"
                    style={{ zIndex: 30 - rank }}
                    initial={false}
                    animate={{ scale: 1 - rank * 0.05, y: rank * 12 }}
                    transition={
                      reduce
                        ? { duration: 0 }
                        : { type: "spring", stiffness: 300, damping: 30 }
                    }
                  >
                    {items[itemIndex]}
                  </motion.div>
                );
              })}
          </AnimatePresence>

          {order.length === 0 ? (
            <div className="absolute inset-0 grid place-items-center rounded-2xl border border-dashed border-border text-sm text-muted-foreground">
              No more cards
            </div>
          ) : null}
        </div>

        <div className="flex items-center gap-4">
          <button
            type="button"
            onClick={() => swipe("left")}
            onKeyDown={handleKey}
            disabled={order.length === 0}
            aria-label={actions?.left ?? "Skip"}
            className="grid size-12 place-items-center rounded-full border border-border bg-card text-destructive shadow-sm [transition:transform_150ms,background_150ms] hover:bg-accent active:scale-95 disabled:opacity-40"
          >
            ✕
          </button>
          <button
            type="button"
            onClick={() => swipe("right")}
            onKeyDown={handleKey}
            disabled={order.length === 0}
            aria-label={actions?.right ?? "Like"}
            className="grid size-12 place-items-center rounded-full border border-border bg-card text-primary shadow-sm [transition:transform_150ms,background_150ms] hover:bg-accent active:scale-95 disabled:opacity-40"
          >
            ♥
          </button>
        </div>
      </div>
    );
  },
);
SwipeDeck.displayName = "SwipeDeck";

export { SwipeDeck };
